 using System.Runtime.InteropServices;
 using System.Windows.Forms;
 using System.Windows.Forms.Design;

 public partial class MyControl : UserControl
 {
     private readonly StatusStrip _statusStrip;

     public string DisplayName { get; set; }
     public int MaxItems { get; set; }

     public MyControl()
     {
         // .NET 9: StatusStrip defaults to ToolStripRenderMode.System instead of
         // ManagerRenderMode. Restore .NET 8 visual appearance explicitly.
         _statusStrip = new StatusStrip
         {
             RenderMode = ToolStripRenderMode.ManagerRenderMode
         };
         Controls.Add(_statusStrip);
     }

     // .NET 9: DropDownControl(null) now throws ArgumentNullException.
     // Guard against null before calling.
     public void ShowDropDown(IWindowsFormsEditorService editorService, Control? control)
     {
         if (control is null)
             return;

         editorService.DropDownControl(control);
     }

     // .NET 9: Use source-generated LibraryImport instead of DllImport
     // for better trimming and AOT compatibility.
     [LibraryImport("user32.dll", EntryPoint = "MessageBoxW", StringMarshalling = StringMarshalling.Utf16)]
     internal static partial int NativeMessageBox(nint hWnd, string text, string caption, uint type);
 }
